## FILE 1: C:\Users\User\citedby-public\pages\Analyze.tsx

Gold-themed version of the audit page with 4-step animation:

```tsx
import React, { useState, useEffect } from 'react';
import { Search, ShieldCheck, TrendingUp, Sparkles, Globe, Bot, BarChart3, CheckCircle } from 'lucide-react';

const analysisSteps = [
  { icon: Globe, label: 'Crawl du site web...', duration: 2000 },
  { icon: Bot, label: 'Interrogation des IA (ChatGPT, Claude, Gemini, AI Overviews)...', duration: 3000 },
  { icon: BarChart3, label: 'Analyse des 50+ criteres AEO...', duration: 2500 },
  { icon: CheckCircle, label: 'Generation du rapport...', duration: 1500 },
];

interface AnalyzeProps {
  onAnalyze: (url: string) => void;
  isAnalyzing: boolean;
}

const Analyze: React.FC<AnalyzeProps> = ({ onAnalyze, isAnalyzing }) => {
  const [inputUrl, setInputUrl] = useState('');
  const [currentStep, setCurrentStep] = useState(0);

  useEffect(() => {
    if (!isAnalyzing) { setCurrentStep(0); return; }
    setCurrentStep(0);
    const timers: ReturnType<typeof setTimeout>[] = [];
    let accumulated = 0;
    analysisSteps.forEach((s, i) => {
      if (i > 0) {
        accumulated += analysisSteps[i - 1].duration;
        timers.push(setTimeout(() => setCurrentStep(i), accumulated));
      }
    });
    return () => timers.forEach(clearTimeout);
  }, [isAnalyzing]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (inputUrl && !isAnalyzing) onAnalyze(inputUrl);
  };

  return (
    <div className="w-full px-4 min-h-[80vh] flex flex-col items-center justify-center animate-in fade-in duration-500">
      <div className="text-center mb-10 space-y-4">
        <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/[0.04] border border-white/[0.08] text-amber-400 text-sm font-medium">
          <Sparkles size={14} /><span>Audit AEO & GEO Instantane</span>
        </div>
        <h1 className="text-4xl md:text-5xl font-sans font-bold text-white">Analysez votre <span className="gradient-text">visibilite IA</span></h1>
        <p className="text-xl text-gray-500 max-w-2xl mx-auto">Decouvrez comment les moteurs de reponse percoivent votre contenu et obtenez un plan d'action.</p>
      </div>
      <div className="w-full max-w-3xl relative z-10">
        <div className="absolute inset-0 bg-amber-500/10 blur-3xl rounded-full opacity-20 -z-10"></div>
        <form onSubmit={handleSubmit}>
          <div className="ninja-card p-8">
            <div className="flex items-center gap-3">
              <Search className="text-gray-500 shrink-0" size={24} />
              <input type="url" required placeholder="https://votre-site.com" className="w-full bg-[#111111] border border-white/[0.08] rounded-xl focus:ring-1 focus:ring-amber-500/30 focus:border-amber-500/30 text-white placeholder-gray-500 text-lg px-4 py-4" value={inputUrl} onChange={(e) => setInputUrl(e.target.value)} autoFocus />
              <button type="submit" disabled={isAnalyzing} className={`btn-gradient px-8 py-4 shrink-0 transition-all transform hover:scale-105 ${isAnalyzing ? '!bg-gray-600 cursor-not-allowed opacity-60' : ''}`}>{isAnalyzing ? 'Analyse...' : 'Lancer l\'audit'}</button>
            </div>
          </div>
        </form>
        {!isAnalyzing && (
          <div className="flex justify-center gap-8 mt-8 text-sm text-gray-500">
            <span className="flex items-center gap-2"><ShieldCheck size={16} className="text-amber-400"/> Analyse Securisee</span>
            <span className="flex items-center gap-2"><TrendingUp size={16} className="text-amber-400"/> +50 Criteres GEO</span>
          </div>
        )}
        {isAnalyzing && (
          <div className="mt-8 w-full max-w-md mx-auto space-y-3 animate-in fade-in duration-300">
            {analysisSteps.map((step, i) => {
              const StepIcon = step.icon;
              const isActive = i === currentStep;
              const isDone = i < currentStep;
              return (
                <div key={i} className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-500 ${isActive ? 'bg-amber-500/10 border border-amber-500/20' : isDone ? 'bg-white/[0.02] border border-white/[0.04]' : 'opacity-40 border border-transparent'}`}>
                  <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 transition-all duration-300 ${isDone ? 'bg-emerald-500/20' : isActive ? 'bg-amber-500/20' : 'bg-white/[0.04]'}`}>
                    {isDone ? <CheckCircle size={16} className="text-emerald-400" /> : <StepIcon size={16} className={isActive ? 'text-amber-400 animate-pulse' : 'text-gray-600'} />}
                  </div>
                  <span className={`text-sm font-medium transition-colors duration-300 ${isDone ? 'text-emerald-400' : isActive ? 'text-amber-300' : 'text-gray-600'}`}>{step.label}</span>
                  {isActive && <div className="ml-auto w-4 h-4 border-2 border-amber-400 border-t-transparent rounded-full animate-spin" />}
                </div>
              );
            })}
            <div className="mt-4 w-full h-1.5 bg-white/[0.06] rounded-full overflow-hidden">
              <div className="h-full bg-gradient-to-r from-amber-500 to-amber-600 rounded-full transition-all duration-1000 ease-out" style={{ width: `${((currentStep + 1) / analysisSteps.length) * 100}%` }} />
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Analyze;
```

## FILE 2: C:\Users\User\citedby-public\pages\Results.tsx

Simplified results page without PDF export (no jsPDF/html2canvas). Gold theme.

```tsx
import React, { useState } from 'react';
import { AnalysisResult, CategoryScore, User } from '../types';
import { Info, Share2, ScanLine, CheckCircle2, AlertTriangle, XCircle, ArrowLeft } from 'lucide-react';
import ScoreRing from '../components/ScoreRing';

interface Props {
  data: AnalysisResult;
  onBack: () => void;
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
  onNewAnalysis?: () => void;
}

const Results: React.FC<Props> = ({ data, onBack, user, onDeductCredits, onNewAnalysis }) => {
  const categoryScores = Object.values(data.categories) as CategoryScore[];

  const handleShare = async () => {
    try {
      if (navigator.share) {
        await navigator.share({ title: 'Rapport AEO - CitedBy.ai', text: `Analyse AEO pour ${data.url}`, url: window.location.href });
      } else {
        await navigator.clipboard.writeText(window.location.href);
        alert('Lien copie !');
      }
    } catch {}
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'success': return <CheckCircle2 size={14} className="text-emerald-400" />;
      case 'warning': return <AlertTriangle size={14} className="text-amber-400" />;
      case 'error': return <XCircle size={14} className="text-red-400" />;
      default: return <Info size={14} className="text-gray-400" />;
    }
  };

  return (
    <div className="w-full px-4 pb-20 pt-6 relative">
      {/* Header */}
      <div className="flex flex-col md:flex-row items-start md:items-center justify-between mb-8 gap-6 pt-6">
        <div>
          <button onClick={onBack} className="flex items-center gap-2 text-gray-500 hover:text-white text-sm mb-4 transition-colors"><ArrowLeft size={16} /> Retour</button>
          <h1 className="text-3xl font-bold text-white mb-2">Rapport d'<span className="gradient-text">Audit AEO</span></h1>
          <p className="text-gray-500 text-sm">{data.url} — {new Date(data.timestamp).toLocaleDateString()}</p>
        </div>
        <div className="flex items-center gap-3">
          <button onClick={handleShare} className="flex items-center gap-2 px-4 py-2.5 rounded-xl border border-white/[0.08] bg-white/[0.04] hover:bg-white/[0.08] text-gray-300 text-sm transition-colors"><Share2 size={16} /> Partager</button>
          {onNewAnalysis && <button onClick={onNewAnalysis} className="btn-gradient px-6 py-2.5 text-sm font-bold flex items-center gap-2"><ScanLine size={16} /> Nouvel audit</button>}
        </div>
      </div>

      {/* Global Score */}
      <div className="ninja-card p-8 mb-8">
        <div className="flex flex-col md:flex-row items-center gap-8">
          <ScoreRing score={data.globalScore} size={180} strokeWidth={12} />
          <div className="flex-1">
            <h2 className="text-2xl font-bold text-white mb-2">Score Global</h2>
            <p className="text-gray-400 mb-4">Votre site obtient un score de {data.globalScore}/100 sur les criteres AEO.</p>
            <div className="flex items-center gap-6">
              <div className="text-center"><div className="text-2xl font-bold text-amber-400">{data.aiCitation.probability}%</div><div className="text-xs text-gray-500">Citation IA</div></div>
              <div className="text-center"><div className="text-2xl font-bold text-white">{data.recommendations.length}</div><div className="text-xs text-gray-500">Recommandations</div></div>
              <div className="text-center"><div className="text-2xl font-bold text-white">{categoryScores.length}</div><div className="text-xs text-gray-500">Categories</div></div>
            </div>
          </div>
        </div>
      </div>

      {/* AI Citation Preview */}
      <div className="ninja-card p-6 mb-8">
        <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2"><Info size={18} className="text-amber-400" /> Apercu Citation IA</h3>
        <div className="grid md:grid-cols-2 gap-4">
          <div className="p-4 rounded-xl bg-white/[0.02] border border-white/[0.06]">
            <div className="text-xs font-bold text-gray-500 uppercase mb-2">Avant optimisation</div>
            <p className="text-gray-400 text-sm italic">{data.aiCitation.before}</p>
          </div>
          <div className="p-4 rounded-xl bg-amber-500/[0.04] border border-amber-500/[0.12]">
            <div className="text-xs font-bold text-amber-400 uppercase mb-2">Apres optimisation</div>
            <p className="text-gray-300 text-sm italic">{data.aiCitation.after}</p>
          </div>
        </div>
      </div>

      {/* Categories */}
      <div className="mb-8">
        <h3 className="text-xl font-bold text-white mb-6">Detail par <span className="gradient-text">categorie</span></h3>
        <div className="grid md:grid-cols-2 gap-4">
          {categoryScores.map((cat, idx) => (
            <div key={idx} className="ninja-card p-6">
              <div className="flex items-center justify-between mb-4">
                <h4 className="text-white font-bold">{cat.name}</h4>
                <div className={`text-sm font-bold ${cat.score >= 80 ? 'text-amber-300' : cat.score >= 60 ? 'text-amber-400' : cat.score >= 40 ? 'text-amber-500' : 'text-red-400'}`}>{cat.score}/100</div>
              </div>
              <div className="w-full h-2 bg-white/[0.06] rounded-full overflow-hidden mb-4">
                <div className={`h-full rounded-full transition-all duration-1000 ${cat.score >= 80 ? 'bg-amber-400' : cat.score >= 60 ? 'bg-amber-500' : cat.score >= 40 ? 'bg-amber-600' : 'bg-red-500'}`} style={{ width: `${cat.score}%` }} />
              </div>
              <div className="space-y-2">
                {cat.items.map((item, i) => (
                  <div key={i} className="flex items-start gap-2 text-sm">
                    {getStatusIcon(item.status)}
                    <span className="text-gray-400">{item.message}</span>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Recommendations */}
      <div>
        <h3 className="text-xl font-bold text-white mb-6">Recommandations <span className="gradient-text">prioritaires</span></h3>
        <div className="space-y-3">
          {data.recommendations.map((rec, idx) => (
            <div key={rec.id} className="ninja-card p-5 flex items-start gap-4">
              <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 text-xs font-bold ${
                rec.priority === 'critical' ? 'bg-red-500/20 text-red-400' :
                rec.priority === 'high' ? 'bg-amber-500/20 text-amber-400' :
                rec.priority === 'medium' ? 'bg-blue-500/20 text-blue-400' :
                'bg-gray-500/20 text-gray-400'
              }`}>{idx + 1}</div>
              <div className="flex-1">
                <div className="flex items-center gap-2 mb-1">
                  <h4 className="text-white font-semibold text-sm">{rec.title}</h4>
                  <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase ${
                    rec.priority === 'critical' ? 'bg-red-500/15 text-red-400' :
                    rec.priority === 'high' ? 'bg-amber-500/15 text-amber-400' :
                    rec.priority === 'medium' ? 'bg-blue-500/15 text-blue-400' :
                    'bg-gray-500/15 text-gray-400'
                  }`}>{rec.priority}</span>
                </div>
                <p className="text-gray-500 text-sm">{rec.description}</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Results;
```

## FILE 3: C:\Users\User\citedby-public\pages\Dashboard.tsx

Gold-themed dashboard with 4 KPIs, chart, recent analyses table. Simplified action cards (4 instead of 8).

```tsx
import React, { useState, useEffect, useRef } from 'react';
import { Plus, Bell, Search, ChevronLeft, ChevronRight, TrendingUp, AlertTriangle, Fuel, BarChart3, Target, ArrowUpRight, ArrowDownRight, Store } from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';
import { AnalysisResult } from '../types';

const useCountUp = (target: number, duration = 1200) => {
  const [count, setCount] = useState(0);
  const ref = useRef<HTMLDivElement>(null);
  useEffect(() => {
    const observer = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting) {
        const startTime = performance.now();
        const step = (now: number) => {
          const progress = Math.min((now - startTime) / duration, 1);
          const eased = 1 - Math.pow(1 - progress, 3);
          setCount(Math.round(eased * target));
          if (progress < 1) requestAnimationFrame(step);
        };
        requestAnimationFrame(step);
        observer.disconnect();
      }
    }, { threshold: 0.3 });
    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, [target, duration]);
  return { count, ref };
};

interface DashboardProps {
  onBack: () => void;
  history: AnalysisResult[];
  onView: (analysis: AnalysisResult) => void;
  onNavigate: (view: any) => void;
}

type TableRow = { url: string; score: number; citation: string; date: string; status: string; statusClass: string; original?: AnalysisResult };

const Dashboard: React.FC<DashboardProps> = ({ onBack, history, onView, onNavigate }) => {
  const scoreKpi = useCountUp(78);
  const citationKpi = useCountUp(68);
  const projectsKpi = useCountUp(5, 800);
  const alertsKpi = useCountUp(3, 800);

  const demoData: TableRow[] = [
    { url: 'example.com/article-1', score: 85, citation: '78%', date: 'Il y a 2h', status: 'Excellent', statusClass: 'bg-amber-400/20 text-amber-300' },
    { url: 'myblog.com/guide-seo', score: 72, citation: '65%', date: 'Il y a 5h', status: 'Bon', statusClass: 'bg-amber-500/20 text-amber-400' },
    { url: 'tech-news.io/ai-trends', score: 88, citation: '82%', date: 'Hier', status: 'Excellent', statusClass: 'bg-amber-400/20 text-amber-300' },
    { url: 'startup.co/blog/growth', score: 58, citation: '42%', date: 'Hier', status: 'Moyen', statusClass: 'bg-blue-500/20 text-blue-400' },
    { url: 'ecommerce.shop/products', score: 91, citation: '88%', date: 'Il y a 2 jours', status: 'Excellent', statusClass: 'bg-amber-400/20 text-amber-300' },
  ];

  const tableData: TableRow[] = history.length > 0 ? history.map(h => ({
    url: new URL(h.url).hostname + new URL(h.url).pathname,
    score: h.globalScore,
    citation: `${h.aiCitation.probability}%`,
    date: new Date(h.timestamp).toLocaleDateString(),
    status: h.globalScore >= 80 ? 'Excellent' : h.globalScore >= 60 ? 'Bon' : 'Moyen',
    statusClass: h.globalScore >= 80 ? 'bg-amber-400/20 text-amber-300' : h.globalScore >= 60 ? 'bg-amber-500/20 text-amber-400' : 'bg-blue-500/20 text-blue-400',
    original: h
  })) : demoData;

  const chartData = [
    { day: 'Lun', score: 72, citations: 45 },
    { day: 'Mar', score: 75, citations: 52 },
    { day: 'Mer', score: 68, citations: 48 },
    { day: 'Jeu', score: 82, citations: 61 },
    { day: 'Ven', score: 79, citations: 58 },
    { day: 'Sam', score: 85, citations: 64 },
    { day: 'Dim', score: 88, citations: 70 },
  ];

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload?.length) {
      return (<div className="bg-[#111111] border border-white/10 rounded-xl p-3 shadow-xl"><p className="text-gray-400 text-xs mb-1">{label}</p>{payload.map((entry: any, i: number) => (<p key={i} className="text-sm font-bold" style={{ color: entry.color }}>{entry.name === 'score' ? 'Score' : 'Citations'}: {entry.value}{entry.name === 'citations' ? '%' : '/100'}</p>))}</div>);
    }
    return null;
  };

  return (
    <div className="w-full px-6 py-8">
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <h1 className="text-3xl font-bold font-sans text-white">Dashboard <span className="gradient-text">Public</span></h1>
        <div className="flex items-center gap-4 w-full md:w-auto">
          <button onClick={() => document.dispatchEvent(new KeyboardEvent('keydown', { key: 'k', ctrlKey: true, bubbles: true }))} className="relative flex items-center gap-2 bg-[#111111] border border-white/[0.08] rounded-xl py-2.5 pl-4 pr-3 text-sm text-gray-500 hover:border-amber-500/30 transition-colors w-full md:w-64 cursor-pointer"><Search size={16} /><span className="flex-1 text-left">Rechercher...</span><kbd className="hidden sm:flex items-center gap-0.5 px-1.5 py-0.5 text-[10px] text-gray-600 bg-white/[0.04] border border-white/[0.08] rounded-md font-mono">Ctrl+K</kbd></button>
          <button onClick={() => onNavigate('analyze')} className="btn-gradient text-white font-bold px-6 py-2.5 rounded-full flex items-center gap-2 whitespace-nowrap"><Plus size={18} /> Nouvelle analyse</button>
        </div>
      </div>

      {/* Quick Actions */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
        {[
          { icon: Fuel, label: 'Gas Station', color: 'text-amber-400', view: 'recharge' },
          { icon: Bell, label: 'Alertes', color: 'text-red-400', view: 'alerts' },
          { icon: Store, label: 'Marketplace', color: 'text-amber-300', view: 'marketplace' },
          { icon: BarChart3, label: 'Monitoring', color: 'text-blue-400', view: 'monitoring' },
        ].map((a, i) => (
          <button key={i} onClick={() => onNavigate(a.view)} className="ninja-card p-6 flex flex-col items-center justify-center gap-3 transition-all hover:-translate-y-1 group w-full">
            <a.icon size={28} className={a.color} />
            <span className="text-sm font-semibold text-gray-300 group-hover:text-white">{a.label}</span>
          </button>
        ))}
      </div>

      {/* KPIs */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
        <div className="ninja-card p-5" ref={scoreKpi.ref}><div className="flex items-center gap-3 mb-3"><div className="w-10 h-10 rounded-full bg-amber-500/20 flex items-center justify-center"><TrendingUp size={20} className="text-amber-400" /></div></div><div className="text-2xl font-bold text-white">{scoreKpi.count}<span className="text-sm text-gray-500 font-normal">/100</span></div><div className="text-sm text-gray-500 mt-1">Score Moyen</div><div className="flex items-center gap-1 mt-2 text-xs text-green-400"><ArrowUpRight size={14} /><span>+5.2% ce mois</span></div></div>
        <div className="ninja-card p-5" ref={citationKpi.ref}><div className="flex items-center gap-3 mb-3"><div className="w-10 h-10 rounded-full bg-green-500/20 flex items-center justify-center"><Target size={20} className="text-green-400" /></div></div><div className="text-2xl font-bold text-white">{citationKpi.count}<span className="text-sm text-gray-500 font-normal">%</span></div><div className="text-sm text-gray-500 mt-1">Taux Citation IA</div><div className="flex items-center gap-1 mt-2 text-xs text-green-400"><ArrowUpRight size={14} /><span>+12% ce mois</span></div></div>
        <div className="ninja-card p-5" ref={projectsKpi.ref}><div className="flex items-center gap-3 mb-3"><div className="w-10 h-10 rounded-full bg-blue-500/20 flex items-center justify-center"><BarChart3 size={20} className="text-blue-400" /></div></div><div className="text-2xl font-bold text-white">{projectsKpi.count}</div><div className="text-sm text-gray-500 mt-1">Projets Actifs</div></div>
        <div className="ninja-card p-5" ref={alertsKpi.ref}><div className="flex items-center gap-3 mb-3"><div className="w-10 h-10 rounded-full bg-red-500/20 flex items-center justify-center"><AlertTriangle size={20} className="text-red-400" /></div></div><div className="text-2xl font-bold text-white">{alertsKpi.count}</div><div className="text-sm text-gray-500 mt-1">Alertes Actives</div><div className="flex items-center gap-1 mt-2 text-xs text-red-400"><ArrowDownRight size={14} /><span>1 critique</span></div></div>
      </div>

      {/* Main Grid */}
      <div className="grid lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 ninja-card p-6">
          <div className="flex justify-between items-center mb-6"><h2 className="text-xl font-bold font-sans text-white">Dernieres <span className="gradient-text">analyses</span></h2></div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead><tr className="text-gray-500 text-sm border-b border-white/[0.06]"><th className="pb-4 font-medium pl-2">URL</th><th className="pb-4 font-medium">Score</th><th className="pb-4 font-medium">Citation IA</th><th className="pb-4 font-medium">Date</th><th className="pb-4 font-medium">Statut</th></tr></thead>
              <tbody className="text-sm">
                {tableData.map((row, idx) => (
                  <tr key={idx} className="border-b border-white/[0.06] last:border-0 hover:bg-white/5 transition-colors cursor-pointer group" onClick={() => row.original ? onView(row.original) : null}>
                    <td className="py-4 pl-2 font-medium text-gray-200 group-hover:text-white">{row.url}</td>
                    <td className="py-4"><span className={row.status === 'Excellent' ? 'text-amber-300 font-bold' : row.status === 'Bon' ? 'text-amber-400 font-bold' : 'text-blue-400 font-bold'}>{row.score}</span><span className="text-gray-600 text-xs">/100</span></td>
                    <td className="py-4 text-gray-300">{row.citation}</td>
                    <td className="py-4 text-gray-500">{row.date}</td>
                    <td className="py-4"><span className={`px-3 py-1 rounded-full text-xs font-bold ${row.statusClass}`}>{row.status}</span></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        <div className="lg:col-span-1 ninja-card p-6 min-h-[300px] flex flex-col">
          <h2 className="text-xl font-bold font-sans text-white mb-6">Evolution des <span className="gradient-text">scores</span></h2>
          <div className="flex-1 w-full min-h-[220px]">
            <ResponsiveContainer width="100%" height="100%">
