        <div className="flex gap-2 flex-wrap">
          {(['all', 'critical', 'warning', 'info', 'resolved'] as const).map(sev => (
            <button key={sev} onClick={() => setFilterSeverity(sev)} className={`px-3 py-2 rounded-xl text-xs font-bold border transition-all ${filterSeverity === sev ? 'border-amber-500/30 bg-amber-500/10 text-amber-300' : 'border-white/[0.06] bg-white/[0.02] text-gray-500 hover:text-white'}`}>{sev === 'all' ? 'Toutes' : SEVERITY_CONFIG[sev].label}</button>
          ))}
        </div>
      </div>

      {/* Summary */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-3 mb-6">
        {(['critical', 'warning', 'info', 'resolved'] as const).map(sev => {
          const cfg = SEVERITY_CONFIG[sev];
